#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,q,st[N][25],a[N ];
int fun(int l,int r)
{
	int len=log2(r-l+1);
	int ans=max(st[l][len],st[r-(1<<len)+1][len]);
	return ans;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<=n;i++)
	{
		cin>>st[i][0];
	}
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n-i+1;j++)
		{
            if(j+(1<<(i-1))>n) break;
			st[j][i]=max(st[j][i-1],st[j+(1<<(i-1))][i-1]);
		}
	}
	for(int i=1;i<=q;i++)
	{
		int l,r;
		cin>>l>>r;
		cout<<fun(l,r)<<'\n';
	}
	return 0;
}
